<?php

namespace SharedDocsManager\Helpers;

if (! defined('ABSPATH')) {
    exit;
}

class Icon_Helper
{
    public static function key_for_file($filename = '', $mime = '')
    {
        $extension = strtolower((string) pathinfo((string) $filename, PATHINFO_EXTENSION));
        $mime = strtolower((string) $mime);

        if ($extension === 'pdf' || $mime === 'application/pdf') {
            return 'pdf';
        }

        if (in_array($extension, array('xls', 'xlsx', 'xlsm', 'xlsb', 'ods', 'csv'), true) || strpos($mime, 'excel') !== false || strpos($mime, 'spreadsheet') !== false) {
            return 'xls';
        }

        if (in_array($extension, array('ppt', 'pptx', 'odp'), true) || strpos($mime, 'powerpoint') !== false || strpos($mime, 'presentation') !== false) {
            return 'ppt';
        }

        if (strpos($mime, 'image/') === 0 || in_array($extension, array('jpg', 'jpeg', 'png', 'gif', 'webp', 'svg'), true)) {
            return 'image';
        }

        if (in_array($extension, array('doc', 'docx', 'odt', 'rtf'), true) || strpos($mime, 'word') !== false || strpos($mime, 'officedocument.wordprocessingml') !== false) {
            return 'doc';
        }

        return 'doc';
    }

    public static function svg_for_resource($resource_type, $filename = '', $mime = '')
    {
        if ($resource_type === 'folder') {
            return self::svg_for_key('folder');
        }

        return self::svg_for_key(self::key_for_file($filename, $mime));
    }

    public static function svg_for_key($key)
    {
        switch ((string) $key) {
            case 'pdf':
                return self::pdf_svg();
            case 'xls':
                return self::xls_svg();
            case 'ppt':
                return self::ppt_svg();
            case 'image':
                return self::image_svg();
            case 'folder':
                return self::folder_svg();
            case 'doc':
            default:
                return self::doc_svg();
        }
    }

